// Helper functions for skill-graph operations
export function getExercisesByArea(area: string): ExerciseNode[] {
  return Object.values(EXERCISE_GRAPH).filter(ex => ex.area === area);
}

export function getExercisePrerequisites(exerciseKey: string): ExerciseNode[] {
  const exercise = EXERCISE_GRAPH[exerciseKey];
  if (!exercise) return [];
  return exercise.prerequisites.map(key => EXERCISE_GRAPH[key]).filter(Boolean);
}

export function getExerciseSuccessors(exerciseKey: string): ExerciseNode[] {
  const exercise = EXERCISE_GRAPH[exerciseKey];
  if (!exercise) return [];
  return exercise.successors.map(key => EXERCISE_GRAPH[key]).filter(Boolean);
}

export function getExercisesBySkill(skillKey: string): ExerciseNode[] {
  return Object.values(EXERCISE_GRAPH).filter(ex =>
    ex.skills_developed.includes(skillKey)
  );
}

export function getSkillsByExercise(exerciseKey: string): string[] {
  const exercise = EXERCISE_GRAPH[exerciseKey];
  return exercise ? exercise.skills_developed : [];
}

